-- SPEC:D.2 — compiled metric view: return_rate (v1) @ grain=all · entity=semantic_order
-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW brain_serving.mv_metric_return_rate_all AS
WITH base AS (
  SELECT
    brand_id,
    channel,
    SUM(CASE WHEN lifecycle_state = 'refunded' THEN 1 ELSE 0 END) AS refunded_orders,
    SUM(CASE WHEN is_terminal THEN 1 ELSE 0 END) AS terminal_orders
  FROM brain_serving.semantic_order
  WHERE ${BRAND_PREDICATE}
  GROUP BY 1, 2
)
SELECT
  brand_id,
  channel,
  refunded_orders,
  terminal_orders,
  (CAST(refunded_orders AS double) / NULLIF(terminal_orders, 0)) AS return_rate
FROM base;
